import{_ as t,o as e,c as r,a2 as l}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"北海公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/beihai-park.md","filePath":"parks/beihai-park.md","lastUpdated":null}'),o={name:"parks/beihai-park.md"};function i(h,a,n,d,s,p){return e(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="北海公园" tabindex="-1">北海公园 <a class="header-anchor" href="#北海公园" aria-label="Permalink to &quot;北海公园&quot;">​</a></h1><blockquote><p>&quot;让我们荡起双桨，小船儿推开波浪，海面倒映着美丽的白塔，四周环绕着绿树红墙。&quot; —— 《让我们荡起双桨》</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>北海公园位于北京城中轴线西侧，是世界上现存建园最早、保存最完整的皇家园林之一，也是中国现存历史最悠久的皇家园林。北海历经辽、金、元、明、清五个朝代，已有近千年历史。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">6:00-21:00（旺季），6:30-20:00（淡季）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">门票10元，联票20元（含琼岛、团城）</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜，夏季荷花最美</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6号线北海北站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区文津街1号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="辽金时期" tabindex="-1">辽金时期 <a class="header-anchor" href="#辽金时期" aria-label="Permalink to &quot;辽金时期&quot;">​</a></h3><p>辽代在此修建瑶屿行宫。金大定六年（1166年），金世宗完颜雍在此营建离宫大宁宫，并开挖太液池（即今北海、中海）。琼华岛始建。</p><h3 id="元代" tabindex="-1">元代 <a class="header-anchor" href="#元代" aria-label="Permalink to &quot;元代&quot;">​</a></h3><p>元至元元年（1264年），元世祖忽必烈以太液池和琼华岛为中心营建新都。琼华岛改称万寿山（又称万岁山），成为元大都的核心。</p><h3 id="明代" tabindex="-1">明代 <a class="header-anchor" href="#明代" aria-label="Permalink to &quot;明代&quot;">​</a></h3><p>明永乐年间，以北海为中心修建皇宫，形成&quot;前三海&quot;（北海、中海、南海）的格局。北海成为皇城内苑。</p><h3 id="清代" tabindex="-1">清代 <a class="header-anchor" href="#清代" aria-label="Permalink to &quot;清代&quot;">​</a></h3><p>清顺治八年（1651年），在琼华岛广寒殿旧址建白塔，改称白塔山。乾隆年间大规模扩建，形成今日规模。</p><h3 id="现代" tabindex="-1">现代 <a class="header-anchor" href="#现代" aria-label="Permalink to &quot;现代&quot;">​</a></h3><p>1925年辟为公园，对外开放。1961年被列为全国重点文物保护单位。</p><h2 id="园林布局" tabindex="-1">园林布局 <a class="header-anchor" href="#园林布局" aria-label="Permalink to &quot;园林布局&quot;">​</a></h2><p>北海公园由琼华岛、北岸、东岸三个部分组成。</p><h3 id="琼华岛" tabindex="-1">琼华岛 <a class="header-anchor" href="#琼华岛" aria-label="Permalink to &quot;琼华岛&quot;">​</a></h3><p>琼华岛是北海的核心，岛上有白塔、永安寺、漪澜堂等建筑。</p><h4 id="白塔" tabindex="-1">白塔 <a class="header-anchor" href="#白塔" aria-label="Permalink to &quot;白塔&quot;">​</a></h4><p>白塔建于清顺治八年（1651年），高35.9米，是北京的地标之一。塔身覆以琉璃筒瓦，塔刹为鎏金宝顶。塔内有旋梯可登，但现在不对外开放。</p><p>白塔的修建有两个说法：</p><ul><li><strong>镇邪说</strong>：传说白塔是为了镇压北海中的蛟龙而建</li><li><strong>纪念说</strong>：纪念顺治皇帝出家为僧（一说为多尔衮修建）</li></ul><h4 id="永安寺" tabindex="-1">永安寺 <a class="header-anchor" href="#永安寺" aria-label="Permalink to &quot;永安寺&quot;">​</a></h4><p>永安寺位于白塔山南麓，是白塔寺的组成部分。寺内有法轮殿、正觉殿、普安殿等，供奉释迦牟尼、阿弥陀佛等佛像。</p><h4 id="漪澜堂" tabindex="-1">漪澜堂 <a class="header-anchor" href="#漪澜堂" aria-label="Permalink to &quot;漪澜堂&quot;">​</a></h4><p>漪澜堂位于白塔山北侧，是乾隆皇帝读书之所。堂内陈设典雅，可远眺北岸风光。</p><h3 id="北岸" tabindex="-1">北岸 <a class="header-anchor" href="#北岸" aria-label="Permalink to &quot;北岸&quot;">​</a></h3><p>北岸是北海的主要游览区，有九龙壁、五龙亭、西天梵境、静心斋等景点。</p><h4 id="九龙壁" tabindex="-1">九龙壁 <a class="header-anchor" href="#九龙壁" aria-label="Permalink to &quot;九龙壁&quot;">​</a></h4><p>九龙壁位于北岸澄观堂前，长25.5米，高6.9米，厚1.42米，是中国现存三座九龙壁中最精美的一座。壁上九条龙栩栩如生，全部用七色琉璃砖砌成。</p><h4 id="五龙亭" tabindex="-1">五龙亭 <a class="header-anchor" href="#五龙亭" aria-label="Permalink to &quot;五龙亭&quot;">​</a></h4><p>五龙亭由五座亭子组成，中间最大，两侧对称递减。是皇帝和群臣垂钓、赏景、宴饮的地方。</p><h4 id="西天梵境" tabindex="-1">西天梵境 <a class="header-anchor" href="#西天梵境" aria-label="Permalink to &quot;西天梵境&quot;">​</a></h4><p>西天梵境又称大西天，是一组藏传佛教建筑群。主体建筑大慈真如宝殿，全部用金丝楠木建成，是中国现存最大的楠木殿。</p><h4 id="静心斋" tabindex="-1">静心斋 <a class="header-anchor" href="#静心斋" aria-label="Permalink to &quot;静心斋&quot;">​</a></h4><p>静心斋是清代皇太子读书的地方，又称&quot;乾隆小花园&quot;。园内亭台楼阁、假山池沼，布局精巧，是北海中保存最完整的园中之园。</p><h3 id="东岸" tabindex="-1">东岸 <a class="header-anchor" href="#东岸" aria-label="Permalink to &quot;东岸&quot;">​</a></h3><p>东岸主要景点有濠濮间、画舫斋等。</p><h4 id="濠濮间" tabindex="-1">濠濮间 <a class="header-anchor" href="#濠濮间" aria-label="Permalink to &quot;濠濮间&quot;">​</a></h4><p>濠濮间是乾隆皇帝垂钓之所，园内有假山、水池、曲桥，环境清幽。</p><h4 id="画舫斋" tabindex="-1">画舫斋 <a class="header-anchor" href="#画舫斋" aria-label="Permalink to &quot;画舫斋&quot;">​</a></h4><p>画舫斋是乾隆皇帝的书斋，临水而建，形似画舫，故名。</p><h2 id="文化故事" tabindex="-1">文化故事 <a class="header-anchor" href="#文化故事" aria-label="Permalink to &quot;文化故事&quot;">​</a></h2><h3 id="让我们荡起双桨" tabindex="-1">让我们荡起双桨 <a class="header-anchor" href="#让我们荡起双桨" aria-label="Permalink to &quot;让我们荡起双桨&quot;">​</a></h3><p>1955年，长春电影制片厂拍摄电影《祖国的花朵》，插曲《让我们荡起双桨》在此取景。歌曲描写的就是北海公园的景象：白塔、绿树红墙、小船、波浪。这首歌至今广为传唱，成为几代人的童年记忆。</p><h3 id="白塔的传说" tabindex="-1">白塔的传说 <a class="header-anchor" href="#白塔的传说" aria-label="Permalink to &quot;白塔的传说&quot;">​</a></h3><p>民间传说，北海下面有一条恶龙，经常兴风作浪。顺治皇帝命人修建白塔镇压恶龙，并在塔下埋入大量佛经和法器，以镇邪祟。</p><p>另一个说法是，顺治皇帝深爱董鄂妃，董鄂妃去世后，顺治悲痛欲绝，欲出家为僧。太后和群臣极力劝阻，最终顺治未能出家，但修建了这座白塔，以示向佛之心。</p><h3 id="九龙壁的秘密" tabindex="-1">九龙壁的秘密 <a class="header-anchor" href="#九龙壁的秘密" aria-label="Permalink to &quot;九龙壁的秘密&quot;">​</a></h3><p>九龙壁上九条龙的腹部都有一块白色琉璃，与整体的七色彩不同。传说当年烧制时，工匠不慎烧坏了一块琉璃砖，眼看工期将至，工匠急中生智，用楠木雕成龙腹，涂上白漆，竟瞒过了检查官员的眼睛。这个故事体现了古代工匠的智慧。</p><h3 id="快雪堂与王羲之" tabindex="-1">快雪堂与王羲之 <a class="header-anchor" href="#快雪堂与王羲之" aria-label="Permalink to &quot;快雪堂与王羲之&quot;">​</a></h3><p>快雪堂是收藏王羲之《快雪时晴帖》的地方。乾隆年间，乾隆皇帝将《快雪时晴帖》及历代名家的题跋刻石，建堂收藏，故名快雪堂。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>南门 → 团城 → 永安桥 → 琼华岛（白塔、永安寺、漪澜堂） → 游船至北岸 → 九龙壁 → 五龙亭 → 西天梵境 → 静心斋 → 北门</p><p><strong>深度路线（约4小时）</strong>：</p><p>南门 → 团城 → 永安桥 → 琼华岛（白塔、永安寺、漪澜堂、阅古楼） → 游船 → 北岸（九龙壁、五龙亭、西天梵境、静心斋、快雪堂、铁影壁） → 东岸（濠濮间、画舫斋） → 东门</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>联票建议</strong>：建议购买联票，可登白塔和参观团城</li><li><strong>游船体验</strong>：可租船游湖（手划船60元/小时，脚踏船80元/小时），体验&quot;荡起双桨&quot;</li><li><strong>最佳时间</strong>：夏季傍晚，可以看日落和白塔倒影</li><li><strong>避开人流</strong>：早上8点前或下午4点后，避开旅行团</li><li><strong>周边游览</strong>：公园南门对着故宫北门，可安排在一起游览</li></ol><h3 id="四季景色" tabindex="-1">四季景色 <a class="header-anchor" href="#四季景色" aria-label="Permalink to &quot;四季景色&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">春</td><td style="text-align:left;">桃花、杏花盛开，琼岛春阴</td></tr><tr><td style="text-align:left;">夏</td><td style="text-align:left;">荷花满池，绿树成荫，可划船纳凉</td></tr><tr><td style="text-align:left;">秋</td><td style="text-align:left;">银杏金黄，菊花展览</td></tr><tr><td style="text-align:left;">冬</td><td style="text-align:left;">雪景白塔，冰上活动</td></tr></tbody></table><h2 id="与中海、南海的关系" tabindex="-1">与中海、南海的关系 <a class="header-anchor" href="#与中海、南海的关系" aria-label="Permalink to &quot;与中海、南海的关系&quot;">​</a></h2><p>北海与中海、南海合称&quot;三海&quot;，都是古代皇家园林。民国时期，中南海成为政府办公区，北海辟为公园。现在三海之中，只有北海对公众开放。</p><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>北海是中国古典园林的杰作，集历代园林艺术之大成。它不仅是一座园林，更是中国古代政治、文化、艺术的缩影。</p><hr><p><strong>📍 地址</strong>：北京市西城区文津街1号 <strong>📞 电话</strong>：010-64040610 <strong>🌐 官网</strong>：<a href="http://www.beihaipark.com.cn" target="_blank" rel="noreferrer">www.beihaipark.com.cn</a></p>',71)])])}const c=t(o,[["render",i]]);export{b as __pageData,c as default};
